class Solution:
    def maximumSubarraySum(self, nums, k):
        n = len(nums)
        from collections import defaultdict
        cnt = defaultdict(int)
        cur = 0
        best = 0
        for i in range(n):
            cur += nums[i]
            cnt[nums[i]] += 1
            if i >= k:
                out = nums[i - k]
                cur -= out
                cnt[out] -= 1
                if cnt[out] == 0:
                    del cnt[out]
            if i >= k - 1 and len(cnt) == k:
                if cur > best:
                    best = cur
        return best

