var maximumSubarraySum = function(nums, k) {
    const n = nums.length;
    const cnt = new Map();
    let cur = 0, best = 0;
    for (let i = 0; i < n; i++) {
        cur += nums[i];
        cnt.set(nums[i], (cnt.get(nums[i]) || 0) + 1);
        if (i >= k) {
            const out = nums[i - k];
            cur -= out;
            const c = cnt.get(out) - 1;
            if (c === 0) cnt.delete(out); else cnt.set(out, c);
        }
        if (i >= k - 1 && cnt.size === k) {
            if (cur > best) best = cur;
        }
    }
    return best;
};
